 1→// sidecar/db/index.ts
 2→// SQLite connection manager for sidecar-v2 message persistence.
 3→// Uses better-sqlite3 for synchronous writes (same as backend).
 4→
 5→import Database from "better-sqlite3";
 6→import path from "path";
 7→import fs from "fs";
 8→import os from "os";
 9→import { SCHEMA_SQL, MIGRATIONS } from "./schema";
10→
11→const DEFAULT_DB_PATH = path.join(
12→  process.env.HOME || os.homedir(),
13→  "Library/Application Support/com.opendevs.app/opendevs.db"
14→);
15→
16→let dbInstance: Database.Database | null = null;
17→let dbClosed = false;
18→
19→/**
20→ * Initialize and return the database connection.
21→ * Uses DATABASE_PATH env var if set, otherwise defaults to production path.
22→ */
23→export function initDatabase(): Database.Database {
24→  if (dbInstance) {
25→    return dbInstance;
26→  }
27→  if (dbClosed) {
28→    throw new Error("[SIDECAR-V2] Database was explicitly closed and cannot be re-opened");
29→  }
30→
31→  const dbPath = process.env.DATABASE_PATH || DEFAULT_DB_PATH;
32→
33→  // Ensure parent directory exists
34→  const dbDir = path.dirname(dbPath);
35→  if (!fs.existsSync(dbDir)) {
36→    fs.mkdirSync(dbDir, { recursive: true });
37→  }
38→
39→  console.log("[SIDECAR-V2] Opening database:", dbPath);
40→
41→  try {
42→    dbInstance = new Database(dbPath);
43→    // Enable WAL mode for concurrent access (backend may also be writing)
44→    dbInstance.pragma("journal_mode = WAL");
45→    dbInstance.pragma("foreign_keys = ON");
46→    dbInstance.pragma("busy_timeout = 5000");
47→
48→    // Create all tables, indexes, and triggers (idempotent)
49→    dbInstance.exec(SCHEMA_SQL);
50→
51→    // Post-launch migrations: add new columns to existing tables.
52→    // Each ALTER TABLE may fail with "duplicate column" if already applied — skip those.
53→    for (const sql of MIGRATIONS) {
54→      try {
55→        dbInstance.exec(sql);
56→      } catch (e: unknown) {
57→        const msg = e instanceof Error ? e.message : "";
58→        if (!msg.includes("duplicate column")) throw e;
59→      }
60→    }
61→
62→    console.log("[SIDECAR-V2] Database connected");
63→    return dbInstance;
64→  } catch (error) {
65→    console.error("[SIDECAR-V2] Failed to open database:", error);
66→    throw error;
67→  }
68→}
69→
70→/**
71→ * Get the initialized database instance.
72→ * Throws if not initialized.
73→ */
74→export function getDatabase(): Database.Database {
75→  if (!dbInstance) {
76→    // Auto-initialize if not done yet
77→    return initDatabase();
78→  }
79→  return dbInstance;
80→}
81→
82→/**
83→ * Close the database connection gracefully.
84→ */
85→export function closeDatabase(): void {
86→  if (dbInstance) {
87→    console.log("[SIDECAR-V2] Closing database connection");
88→    dbInstance.pragma("optimize");
89→    dbInstance.close();
90→    dbInstance = null;
91→    dbClosed = true;
92→  }
93→}
