  1→// sidecar/agents/claude/claude-session.ts
  2→// Session state management for Claude agent: active sessions, queries,
  3→// settings comparison, termination, and session reuse logic.
  4→
  5→import type { Query, SDKMessage } from "@anthropic-ai/claude-agent-sdk";
  6→import type { QueryOptions } from "../agent-handler";
  7→
  8→// ============================================================================
  9→// Types
 10→// ============================================================================
 11→
 12→/**
 13→ * Mutable session record accumulated during a Claude SDK lifecycle.
 14→ *
 15→ * Lifecycle phases (fields set in each phase):
 16→ *
 17→ *   IDLE (freshly created via handleQuery → setSession):
 18→ *     currentSettings, currentModel, currentMaxThinkingTokens, turnId, cwd
 19→ *     generator/sendMessage/sendTerminate are undefined
 20→ *
 21→ *   ACTIVE (processWithGenerator running):
 22→ *     All fields populated. generator + sendMessage + sendTerminate set
 23→ *     by processWithGenerator after SDK query starts.
 24→ *
 25→ *   TERMINATED (terminateSession called, awaiting finally cleanup):
 26→ *     generator + sendMessage deleted. sendTerminate fired.
 27→ *     Session object is kept alive so processWithGenerator's finally block
 28→ *     can compare `currentSession === session` (reference identity check)
 29→ *     to avoid clobbering a rapid re-query's fresh session.
 30→ *
 31→ * Use `isSessionActive(session)` to check if a session is in the ACTIVE phase.
 32→ */
 33→export interface SessionState {
 34→  generator?: AsyncIterator<SDKMessage>;
 35→  sendMessage?: (message: string) => void;
 36→  sendTerminate?: () => void;
 37→  currentSettings?: {
 38→    claudeEnvVars?: string;
 39→    additionalDirectories?: string[];
 40→    chromeEnabled?: boolean;
 41→    strictDataPrivacy?: boolean;
 42→  };
 43→  currentModel?: string;
 44→  currentMaxThinkingTokens?: number;
 45→  turnId?: string;
 46→  cwd?: string;
 47→  /** One-shot flag: true after the first SDK message's session_id has been persisted to DB */
 48→  agentSessionIdCaptured?: boolean;
 49→  /** Set by handleCancel before close() — checked by post-loop path to persist cancellation */
 50→  cancelledByUser?: boolean;
 51→}
 52→
 53→// ============================================================================
 54→// State
 55→// ============================================================================
 56→
 57→const activeSessions = new Map<string, SessionState>();
 58→const queries = new Map<string, Query>();
 59→
 60→// ============================================================================
 61→// Public API
 62→// ============================================================================
 63→
 64→export function getSession(sessionId: string): SessionState | undefined {
 65→  return activeSessions.get(sessionId);
 66→}
 67→
 68→export function setSession(sessionId: string, session: SessionState): void {
 69→  activeSessions.set(sessionId, session);
 70→}
 71→
 72→export function deleteSession(sessionId: string): void {
 73→  activeSessions.delete(sessionId);
 74→}
 75→
 76→export function getQuery(sessionId: string): Query | undefined {
 77→  return queries.get(sessionId);
 78→}
 79→
 80→export function setQuery(sessionId: string, query: Query): void {
 81→  queries.set(sessionId, query);
 82→}
 83→
 84→export function deleteQuery(sessionId: string): void {
 85→  queries.delete(sessionId);
 86→}
 87→
 88→/**
 89→ * Check if a session is in the ACTIVE phase (generator running, can send messages).
 90→ * Use this instead of manually checking `session.generator && session.sendMessage`.
 91→ */
 92→export function isSessionActive(session: SessionState | undefined): session is SessionState & {
 93→  generator: AsyncIterator<SDKMessage>;
 94→  sendMessage: (message: string) => void;
 95→} {
 96→  return !!session?.generator && !!session?.sendMessage;
 97→}
 98→
 99→/**
100→ * Compares old session settings with new options to determine
101→ * if the generator needs to be recreated.
102→ */
103→export function settingsChanged(
104→  oldSettings: SessionState["currentSettings"],
105→  newSettings: QueryOptions | undefined
106→): boolean {
107→  if (!oldSettings) return true;
108→
109→  if (oldSettings.claudeEnvVars !== newSettings?.claudeEnvVars) {
110→    return true;
111→  }
112→
113→  const oldDirs = oldSettings.additionalDirectories ?? [];
114→  const newDirs = newSettings?.additionalDirectories ?? [];
115→  if (oldDirs.length !== newDirs.length) return true;
116→  for (let i = 0; i < oldDirs.length; i++) {
117→    if (oldDirs[i] !== newDirs[i]) return true;
118→  }
119→
120→  if ((oldSettings.chromeEnabled ?? false) !== (newSettings?.chromeEnabled ?? false)) {
121→    return true;
122→  }
123→
124→  if ((oldSettings.strictDataPrivacy ?? false) !== (newSettings?.strictDataPrivacy ?? false)) {
125→    return true;
126→  }
127→
128→  return false;
129→}
130→
131→/**
132→ * Terminates the generator for a session (sends terminate signal,
133→ * cleans up generator and sendMessage references).
134→ */
135→export function terminateSession(sessionId: string): void {
136→  const session = activeSessions.get(sessionId);
137→  if (session && session.sendTerminate) {
138→    session.sendTerminate();
139→    delete session.generator;
140→    delete session.sendMessage;
141→  }
142→  // Note: queries cleanup is owned by processWithGenerator's finally block.
143→  // We only signal termination here — the finally block calls deleteQuery + deleteSession.
144→}
