349→   * Broadcast a notification to all connected tunnels.

 1→import { Hono } from 'hono';
 2→import { triggerWatcherTick } from '../services/relay.service';
 3→import { invalidate } from '../services/query-engine';
 4→import { NOTIFY_SESSION_MESSAGE, NOTIFY_SESSION_STATUS, NOTIFY_SESSION_UPDATED, SIDECAR_NOTIFY_EVENTS, type QueryResource, type SidecarNotifyEvent } from '../../../shared/events';
 5→
 6→const app = new Hono();
 7→
 8→/**
 9→ * POST /notify
10→ *
11→ * Receives batched notifications from the sidecar after DB writes.
12→ * Triggers instant dashboard updates instead of waiting for polling.
13→ *
14→ * Notification events:
15→ * - session:message  → trigger watcher tick (pushes message deltas to watching clients)
16→ * - session:status   → invalidate workspaces, sessions, stats
17→ * - session:updated  → invalidate workspaces, sessions
18→ */
19→app.post('/notify', async (c) => {
20→  const { notifications } = await c.req.json<{
21→    notifications: Array<{ event: string; sessionId?: string }>;
22→  }>();
23→
24→  if (!Array.isArray(notifications) || notifications.length === 0) {
25→    return c.json({ ok: true });
26→  }
27→
28→  let needsWatcherTick = false;
29→
30→  // Map sidecar events → query resources for push-first invalidation
31→  const INVALIDATION_MAP: Record<SidecarNotifyEvent, QueryResource[]> = {
32→    [NOTIFY_SESSION_MESSAGE]: ['messages'],
33→    [NOTIFY_SESSION_STATUS]:  ['workspaces', 'sessions', 'stats'],
34→    [NOTIFY_SESSION_UPDATED]: ['workspaces', 'sessions'],
35→  };
36→  const resourcesToInvalidate = new Set<QueryResource>();
37→
38→  for (const n of notifications) {
39→    if (n.event === NOTIFY_SESSION_MESSAGE) {
40→      needsWatcherTick = true;
41→    }
42→    if ((SIDECAR_NOTIFY_EVENTS as readonly string[]).includes(n.event)) {
43→      const resources = INVALIDATION_MAP[n.event as SidecarNotifyEvent];
44→      resources.forEach((r) => resourcesToInvalidate.add(r));
45→    }
46→  }
47→
48→  // Trigger watcher immediately so watching clients get message deltas
49→  if (needsWatcherTick) {
50→    triggerWatcherTick();
51→  }
52→
53→  // Push-first invalidation for query subscribers
54→  if (resourcesToInvalidate.size > 0) {
55→    invalidate([...resourcesToInvalidate]);
56→  }
57→
58→  return c.json({ ok: true });
59→});
60→
61→export default app;
