 65→// ============================================================================
 66→// buildPromptIterable — parses queue messages into SDK-compatible user turns
 67→// ============================================================================
 68→
 69→/**
 70→ * Wraps an AsyncQueue of raw prompt strings into the async-iterable format
 71→ * expected by the Claude Agent SDK. Handles both plain text and JSON-encoded
 72→ * content blocks (when user attaches images).
 73→ */
 74→function buildPromptIterable(queue: AsyncQueue<string>, sessionId: string) {
 75→  return (async function* () {
 76→    for await (const message of queue) {
 77→      let content: string | unknown[] = message;
 78→      if (message && message.startsWith("[")) {
 79→        try {
 80→          const parsed = JSON.parse(message);
 81→          if (Array.isArray(parsed) && parsed.length > 0 && parsed[0]?.type) {
 82→            content = parsed;
 83→          }
 84→        } catch {
 85→          // Not valid JSON — keep as plain text string
 86→        }
 87→      }
 88→
 89→      yield {
 90→        type: "user" as const,
 91→        message: { role: "user" as const, content },
 92→        parent_tool_use_id: null,
 93→        session_id: sessionId,
 94→      };
 95→    }
 96→  })();
 97→}
