 1→// sidecar/agents/agent-handler.ts
 2→// AgentHandler interface and registry for multi-agent dispatch.
 3→// Each agent type (claude, codex, etc.) implements AgentHandler and
 4→// registers itself in the registry during sidecar startup.
 5→
 6→import { getErrorMessage } from "../../shared/lib/errors";
 7→import type { AgentType, QueryRequest } from "../protocol";
 8→
 9→/** Options passed to handleQuery, validated by QueryRequestSchema in protocol.ts */
10→export type QueryOptions = QueryRequest["options"];
11→
12→/**
13→ * Common interface for all agent handlers.
14→ *
15→ * Each agent implements these 4 lifecycle methods:
16→ * - initialize() — one-time setup (e.g., discover executable)
17→ * - handleQuery() — process a user prompt
18→ * - handleCancel() — cancel a running session
19→ * - handleReset() — tear down generator for a session
20→ */
21→export interface AgentHandler {
22→  readonly agentType: AgentType;
23→
24→  initialize(): { success: boolean; error?: string };
25→
26→  handleQuery(sessionId: string, prompt: string, options: QueryOptions): Promise<void>;
27→
28→  handleCancel(sessionId: string): Promise<void>;
29→
30→  handleReset(sessionId: string): void;
31→}
32→
33→// ============================================================================
34→// Agent Registry
35→// ============================================================================
36→
37→const registry = new Map<AgentType, AgentHandler>();
38→
39→/**
40→ * Registers an agent handler in the registry.
41→ * Overwrites any existing handler for the same agentType.
42→ */
43→export function registerAgent(handler: AgentHandler): void {
44→  registry.set(handler.agentType, handler);
45→}
46→
47→/**
48→ * Retrieves the agent handler for a given type.
49→ * Returns undefined if no handler is registered for that type.
50→ */
51→export function getAgent(type: AgentType): AgentHandler | undefined {
52→  return registry.get(type);
53→}
54→
55→/**
56→ * Initializes all registered agents and returns their results.
57→ * Called once during sidecar startup after all agents are registered.
58→ */
59→export function initializeAllAgents(): Map<AgentType, { success: boolean; error?: string }> {
60→  const results = new Map<AgentType, { success: boolean; error?: string }>();
61→  for (const [type, handler] of registry) {
62→    try {
63→      const result = handler.initialize();
64→      results.set(type, result);
65→    } catch (error) {
66→      results.set(type, {
67→        success: false,
68→        error: getErrorMessage(error),
69→      });
70→    }
71→  }
72→  return results;
73→}
74→
75→/**
76→ * Clears the registry. Used in tests to reset state between runs.
77→ */
78→export function clearAgentRegistry(): void {
79→  registry.clear();
80→}
