 93→/**
 94→ * Fetch messages for a session with smart fallback
 95→ * - Desktop (Tauri): Real-time events, no polling
 96→ * - Web (Browser): Smart polling when session is working
 97→ *
 98→ * Returns Message[] via `select` so downstream consumers are unchanged.
 99→ * Raw cache holds PaginatedMessages for optimistic updates.
100→ */
101→export function useMessages(sessionId: string | null) {
102→  const query = useQuery({
103→    queryKey: queryKeys.sessions.messages(sessionId || ""),
104→    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
105→    enabled: !!sessionId,
106→    // No select — expose full PaginatedMessages for has_older/has_newer.
107→    // All updates are manual: Tauri events do incremental fetch, web mode uses polling hook.
108→    refetchInterval: false,
109→    staleTime: Infinity,
110→  });
111→
112→  return query;
113→}
