131→    []
132→  );
133→
134→  // Build tool result map and parent_tool_use_id map in a single pass.
135→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
136→    const resultMap = new Map();
137→    const parentMap = new Map<string, string>();
138→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
139→
140→    messages.forEach((msg: Message) => {
141→      if (msg.parent_tool_use_id) {
