156→  // Group subagent messages by their parent Task tool_use_id
157→  const subagentMessages = useMemo(() => {
158→    const map = new Map<string, Message[]>();
159→    if (!messages.length) return map;
160→
161→    messages.forEach((msg: Message) => {
162→      const parentId = parentToolUseMap.get(msg.id);
163→      if (parentId) {
164→        if (!map.has(parentId)) map.set(parentId, []);
165→        map.get(parentId)!.push(msg);
166→      }
167→    });
168→
169→    return map;
170→  }, [messages, parentToolUseMap]);
171→
172→  // Get latest user message's sent_at for duration tracking
173→  const latestMessageSentAt = useMemo(() => {
174→    if (!messages.length) return null;
175→
176→    // Find the latest user message
177→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
178→
179→    return latestUserMessage?.sent_at || null;
180→  }, [messages]);
181→
182→  return {
183→    session: sessionQuery.data,
184→    messages,
185→    hasOlder,
186→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
187→    latestMessageSentAt,
188→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
189→    error: sessionQuery.error || messagesQuery.error,
190→    parseContent,
191→    toolResultMap,
192→    parentToolUseMap,
193→    subagentMessages,
194→  };
