 1→// sidecar/agents/codex/codex-session.ts
 2→// Session state management for Codex agent.
 3→// Simpler than Claude's session state since Codex SDK exec mode is non-interactive
 4→// (no mid-turn user messaging, no generator queue pattern).
 5→
 6→// ============================================================================
 7→// Types
 8→// ============================================================================
 9→
10→export interface CodexSessionState {
11→  /** The Codex SDK thread ID (stored in ~/.codex/sessions/) */
12→  threadId?: string;
13→  /** AbortController for cancelling the current run */
14→  abortController?: AbortController;
15→  /** Current model being used */
16→  currentModel?: string;
17→  /** Working directory for this session */
18→  cwd?: string;
19→  /** Whether a query is currently running */
20→  isRunning: boolean;
21→}
22→
23→// ============================================================================
24→// State
25→// ============================================================================
26→
27→const activeSessions = new Map<string, CodexSessionState>();
28→
29→// ============================================================================
30→// Public API
31→// ============================================================================
32→
33→export function getCodexSession(sessionId: string): CodexSessionState | undefined {
34→  return activeSessions.get(sessionId);
35→}
36→
37→export function setCodexSession(sessionId: string, session: CodexSessionState): void {
38→  activeSessions.set(sessionId, session);
39→}
40→
41→export function deleteCodexSession(sessionId: string): void {
42→  activeSessions.delete(sessionId);
43→}
44→
45→/**
46→ * Aborts the current run for a session and marks it as not running.
47→ */
48→export function abortCodexSession(sessionId: string): void {
49→  const session = activeSessions.get(sessionId);
50→  if (session) {
51→    session.abortController?.abort();
52→    session.isRunning = false;
53→  }
54→}
