 52→/**
 53→ * Creates the canUseTool callback for a Claude session.
 54→ * Handles ExitPlanMode approval and file path guards.
 55→ */
 56→export function createCanUseTool(sessionId: string, workingDirectory: string | undefined) {
 57→  return async (toolName: string, input: any, _toolOptions: any) => {
 58→    // Handle plan mode exit approval
 59→    if (toolName === "ExitPlanMode") {
 60→      const currentSession = getSession(sessionId);
 61→
 62→      let response: { approved: boolean; turnId?: string };
 63→      try {
 64→        response = await FrontendClient.requestExitPlanMode({
 65→          sessionId,
 66→          toolInput: input,
 67→        });
 68→      } catch (err) {
 69→        console.error("[canUseTool] ExitPlanMode request failed:", err);
 70→        return {
 71→          behavior: "deny",
 72→          message:
 73→            "Plan approval request failed (frontend may be unavailable or timed out). " +
 74→            "Please wait for the user to reconnect and try again.",
 75→          interrupt: true,
 76→        };
 77→      }
 78→
 79→      if (response.approved) {
 80→        if (response.turnId && currentSession?.cwd) {
 81→          const oldTurnId = currentSession.turnId;
 82→          const newTurnId = response.turnId;
 83→
 84→          if (oldTurnId) {
 85→            createCheckpoint(
 86→              sessionId,
 87→              oldTurnId,
 88→              "end",
 89→              currentSession.cwd,
 90→              "claudeHandler:exitPlanMode"
 91→            );
 92→          }
 93→          currentSession.turnId = newTurnId;
 94→          createCheckpoint(
 95→            sessionId,
 96→            newTurnId,
 97→            "start",
 98→            currentSession.cwd,
 99→            "claudeHandler:exitPlanMode"
100→          );
101→        }
102→
103→        return {
104→          behavior: "allow",
105→          updatedInput: input,
106→          updatedPermissions: [{ type: "setMode", mode: "default", destination: "session" }],
107→        };
108→      } else {
109→        return {
110→          behavior: "deny",
111→          message: "Plan denied by user. Please await a further message for an explanation.",
112→          interrupt: true,
113→        };
114→      }
115→    }
116→
117→    // Guard edit tools against writing outside allowed directories
118→    const editTools = ["Edit", "MultiEdit", "Write", "NotebookEdit"];
119→    if (editTools.includes(toolName)) {
120→      if (workingDirectory) {
121→        const filePath = input.file_path || input.notebook_path || "";
122→        if (filePath) {
123→          let normalizedFilePath: string;
124→          try {
125→            normalizedFilePath = fs.realpathSync(filePath);
126→          } catch {
127→            normalizedFilePath = path.resolve(filePath);
128→          }
129→          const additionalDirectories =
130→            getSession(sessionId)?.currentSettings?.additionalDirectories ?? [];
131→          const allAllowedDirs = [workingDirectory, ...additionalDirectories].map((dir) => {
132→            try {
133→              return fs.realpathSync(dir);
134→            } catch {
135→              return path.resolve(dir);
136→            }
137→          });
138→
139→          if (
140→            !allAllowedDirs.some(
141→              (dir) => normalizedFilePath === dir || normalizedFilePath.startsWith(dir + path.sep)
142→            )
143→          ) {
144→            console.log(
145→              `[canUseTool] BLOCKED: ${toolName} on ${filePath} - outside: ${allAllowedDirs.join(", ")}`
146→            );
147→            return {
148→              behavior: "deny",
149→              message: `Cannot edit files outside allowed directories (${allAllowedDirs.join(", ")}). Attempted: ${filePath}`,
150→            };
151→          }
152→        }
153→      }
154→    }
155→
156→    return { behavior: "allow", updatedInput: input };
157→  };
158→}
