223→  env: Record<string, string>,
224→  options: QueryOptions
225→): Options {
226→  const modelToUse = mapModelForProvider(options?.model, env);
227→  const workingDirectory = options?.cwd;
228→  const permissionMode = (options?.permissionMode ?? "default") as PermissionMode;
