242→    },
243→    settingSources: DEFAULT_SETTING_SOURCES,
244→    canUseTool: createCanUseTool(sessionId, workingDirectory),
245→    additionalDirectories: options?.additionalDirectories ?? [],
246→    env,
247→    disallowedTools: ["AskUserQuestion"],
248→    permissionMode,
249→    hooks: createHooks(sessionId),
250→  };
251→
252→  if (options?.chromeEnabled) {
253→    (sdkOptions as any).extraArgs = { chrome: null };
254→  }
255→
256→  if (options?.resumeSessionAt) {
257→    sdkOptions.resumeSessionAt = options.resumeSessionAt;
258→  }
259→
260→  if (options?.resume) {
261→    sdkOptions.resume = options.resume;
262→  }
263→
264→  if (!options?.strictDataPrivacy) {
265→    sdkOptions.mcpServers = {
266→      opendevs: createOpenDevsMCPServer(sessionId),
267→      ...createNotebookMCPServer(workingDirectory),
268→    };
269→  }
270→
271→  return sdkOptions as Options;
272→}
