104→/** Connect and wait for the "connected" frame. Returns ws + connectionId. */
105→async function connectAndAuth(): Promise<{ ws: WebSocket; connectionId: string }> {
106→  const ws = new WebSocket(`ws://127.0.0.1:${port}/ws`);
107→
108→  const connectionId = await new Promise<string>((resolve, reject) => {
109→    const timeout = setTimeout(() => reject(new Error("WS connect timeout")), 5000);
110→    ws.onmessage = (evt) => {
111→      clearTimeout(timeout);
112→      const msg = JSON.parse(evt.data as string);
113→      if (msg.type === "connected") resolve(msg.connectionId);
114→      else reject(new Error(`Expected connected, got ${msg.type}`));
115→    };
116→    ws.onerror = (err) => {
117→      clearTimeout(timeout);
118→      reject(err);
119→    };
120→  });
121→
122→  return { ws, connectionId };
123→}
