 39→      if (import.meta.env.DEV)
 40→        console.log("[SOCKET] ⚠️  Running in web mode - socket features disabled");
 41→      return;
 42→    }
 43→
 44→    try {
 45→      // Check if Rust already connected during app startup (avoids double-connection bug)
