  1→// sidecar/agents/claude/message-processor.ts
  2→// Processes a single deserialized SDK message: persists to DB, sends to
  3→// frontend, updates stream context. Extracted from the for-await loop body
  4→// in processWithGenerator.
  5→
  6→import { getErrorMessage } from "../../../shared/lib/errors";
  7→import { FrontendClient } from "../../frontend-client";
  8→import { classifyStopReason } from "../error-classifier";
  9→import {
 10→  saveAssistantMessage,
 11→  saveToolResultMessage,
 12→  saveAgentSessionId,
 13→  updateSessionStatus,
 14→} from "../../db/session-writer";
 15→import type { StreamContext } from "./stream-context";
 16→import type { SessionState } from "./claude-session";
 17→
 18→// ============================================================================
 19→// Types
 20→// ============================================================================
 21→
 22→/** Options needed by processMessage that don't change per-message. */
 23→export interface ProcessMessageOptions {
 24→  sessionId: string;
 25→  generatorId: string;
 26→  model: string;
 27→  isResume: boolean;
 28→}
 29→
 30→// ============================================================================
 31→// deserializeMessage
 32→// ============================================================================
 33→
 34→/**
 35→ * Safely serializes and deserializes an SDK message to strip circular
 36→ * references and produce a clean Record<string, unknown>.
 37→ * Returns null if serialization fails (message should be skipped).
 38→ */
 39→export function deserializeMessage(
 40→  message: unknown,
 41→  generatorId: string
 42→): Record<string, unknown> | null {
 43→  try {
 44→    const seen = new WeakSet();
 45→    const messageStr = JSON.stringify(
 46→      message,
 47→      (_key, value) => {
 48→        if (typeof value === "object" && value !== null) {
 49→          if (seen.has(value)) return "[Circular]";
 50→          seen.add(value);
 51→        }
 52→        return value;
 53→      }
 54→    );
 55→    return JSON.parse(messageStr);
 56→  } catch (parseError) {
 57→    console.error(
 58→      `[${generatorId}] Failed to serialize/parse SDK message, skipping:`,
 59→      getErrorMessage(parseError)
 60→    );
 61→    return null;
 62→  }
 63→}
 64→
 65→// ============================================================================
 66→// processMessage
 67→// ============================================================================
 68→
 69→/**
 70→ * Processes a single deserialized SDK message.
 71→ *
 72→ * Side effects (in critical order):
 73→ * 1. Capture agent_session_id (one-shot, first message only, skip on resume)
 74→ * 2. Save assistant message to DB
 75→ * 3. Save tool_result message to DB
 76→ * 4. Send to frontend (AFTER DB writes — ordering is critical)
 77→ * 5. Classify stop_reason and send error (AFTER sendMessage — content before error banner)
 78→ * 6. Detect result/success → set ctx.querySucceeded
 79→ * 7. Detect result/error_during_execution → set ctx.lastResultError
 80→ */
 81→export function processMessage(
 82→  cleanMessage: Record<string, unknown>,
 83→  ctx: StreamContext,
 84→  session: SessionState,
 85→  opts: ProcessMessageOptions
 86→): void {
 87→  // Extract common fields from the deserialized SDK message.
 88→  // cleanMessage is Record<string, unknown> (JSON.parse output), so
 89→  // we narrow once here instead of scattering `as` casts throughout.
 90→  const msg = cleanMessage.message as
 91→    | { id?: string; role?: string; content?: unknown; stop_reason?: string }
 92→    | undefined;
 93→  const parentToolUseId =
 94→    typeof cleanMessage.parent_tool_use_id === "string"
 95→      ? cleanMessage.parent_tool_use_id
 96→      : null;
 97→
 98→  // 1. One-shot: capture SDK session_id on the first message.
 99→  // CRITICAL: Skip capture during resume attempts. When a resume
100→  // fails (result/error_during_execution), the SDK returns a NEW
101→  // session_id that is useless. If we captured it, we'd overwrite
102→  // the original working agent_session_id — permanently lost.
103→  if (!session.agentSessionIdCaptured && cleanMessage.session_id && !opts.isResume) {
104→    const agentSessionId = String(cleanMessage.session_id);
105→    const saveResult = saveAgentSessionId(opts.sessionId, agentSessionId);
106→    if (saveResult.ok) {
107→      session.agentSessionIdCaptured = true;
108→      console.log(`[${opts.generatorId}] Captured agent_session_id: ${agentSessionId}`);
109→    } else {
110→      console.error(
111→        `[${opts.generatorId}] Failed to persist agent_session_id: ${saveResult.error}`
112→      );
113→    }
114→  }
115→
116→  // 2. Persist assistant messages to database (before frontend notification)
117→  if (cleanMessage.type === "assistant" && msg) {
118→    const tDbWrite = Date.now();
119→    const writeResult = saveAssistantMessage(opts.sessionId, msg, opts.model, parentToolUseId);
120→    const dbWriteMs = Date.now() - tDbWrite;
121→    if (!writeResult.ok) {
122→      console.error(
123→        `[${opts.generatorId}] DB write failed for assistant message: ${writeResult.error}`
124→      );
125→    }
126→    if (dbWriteMs > 10) {
127→      console.log(`[TIMING][${opts.generatorId}] saveAssistantMessage took ${dbWriteMs}ms`);
128→    }
129→  }
130→
131→  // 3. Persist user messages with tool_result blocks
132→  if (cleanMessage.type === "user" && msg) {
133→    const content = msg.content;
134→    const hasToolResult =
135→      Array.isArray(content) && content.some((b: any) => b?.type === "tool_result");
136→    if (hasToolResult) {
137→      const tDbWrite = Date.now();
138→      const writeResult = saveToolResultMessage(opts.sessionId, msg, parentToolUseId);
139→      const dbWriteMs = Date.now() - tDbWrite;
140→      if (!writeResult.ok) {
141→        console.error(
142→          `[${opts.generatorId}] DB write failed for tool_result message: ${writeResult.error}`
143→        );
144→      }
145→      if (dbWriteMs > 10) {
146→        console.log(`[TIMING][${opts.generatorId}] saveToolResultMessage took ${dbWriteMs}ms`);
147→      }
148→    }
149→  }
150→
151→  // 4. Send to frontend via JSON-RPC notification (after DB writes)
152→  const tSend = Date.now();
153→  FrontendClient.sendMessage({
154→    id: opts.sessionId,
155→    type: "message",
156→    agentType: "claude",
157→    data: cleanMessage,
158→  });
159→  const sendMs = Date.now() - tSend;
160→  if (sendMs > 5) {
161→    console.log(`[TIMING][${opts.generatorId}] sendMessage took ${sendMs}ms`);
162→  }
163→
164→  // 5. Classify stop_reason (after sendMessage — content before error banner)
165→  if (cleanMessage.type === "assistant" && msg) {
166→    const stopError = classifyStopReason(msg.stop_reason);
167→    if (stopError) {
168→      FrontendClient.sendError({
169→        id: opts.sessionId,
170→        type: "error",
171→        error: stopError.message,
172→        agentType: "claude",
173→        category: stopError.category,
174→      });
175→      updateSessionStatus(opts.sessionId, "error", stopError.message, stopError.category);
176→      ctx.stopReasonError = true;
177→    }
178→  }
179→
180→  // 6. result/success → mark query as succeeded.
181→  // Status transition to "idle" is owned by executeOutcome() in stream-context.ts
182→  // after the streaming loop ends — not here. Doing it here would double-write.
183→  if (cleanMessage.type === "result" && cleanMessage.subtype === "success") {
184→    ctx.querySucceeded = true;
185→  }
186→
187→  // 7. result/error_during_execution → capture for error diagnostics
188→  // NOTE: We intentionally do NOT clear the agent_session_id here.
189→  // Even if the resume failed, the original ID must be preserved.
190→  if (cleanMessage.type === "result" && cleanMessage.subtype === "error_during_execution") {
191→    const errors = cleanMessage.errors as string[] | undefined;
192→    const resultError = Array.isArray(errors) && errors.length > 0
193→      ? errors.join("; ")
194→      : typeof cleanMessage.error === "string"
195→        ? cleanMessage.error
196→        : "unknown";
197→    ctx.lastResultError = resultError;
198→    console.error(`[${opts.generatorId}] result/error_during_execution: ${resultError}`);
199→  }
200→}
201→

  1→// sidecar/agents/claude/stream-context.ts
  2→// Tracks mutable state accumulated during a streaming loop and resolves
  3→// the final outcome. Replaces scattered boolean flags and ~100 lines
  4→// of if/return chains in processWithGenerator's post-loop + catch blocks.
  5→
  6→import { match } from "ts-pattern";
  7→import { getErrorMessage } from "../../../shared/lib/errors";
  8→import { classifyError } from "../error-classifier";
  9→import { persistCancellation, notifyAndRecordError } from "../query-lifecycle";
 10→import { updateSessionStatus } from "../../db/session-writer";
 11→import { getSession, type SessionState } from "./claude-session";
 12→
 13→// ============================================================================
 14→// StreamContext — replaces 5 scattered flags
 15→// ============================================================================
 16→
 17→/**
 18→ * Mutable context accumulated during the for-await streaming loop.
 19→ * Each field has a single writer and clear lifecycle:
 20→ *
 21→ * - querySucceeded:  set once when result/success is received
 22→ * - stopReasonError: set once when classifyStopReason detects an error
 23→ * - messageCount:    incremented per SDK message
 24→ * - lastResultError: set when result/error_during_execution is received
 25→ * - firstMessageTime: timestamp of first SDK message (ms), null until set
 26→ */
 27→export interface StreamContext {
 28→  querySucceeded: boolean;
 29→  stopReasonError: boolean;
 30→  messageCount: number;
 31→  lastResultError: string | null;
 32→  firstMessageTime: number | null;
 33→}
 34→
 35→export function createStreamContext(): StreamContext {
 36→  return {
 37→    querySucceeded: false,
 38→    stopReasonError: false,
 39→    messageCount: 0,
 40→    lastResultError: null,
 41→    firstMessageTime: null,
 42→  };
 43→}
 44→
 45→// ============================================================================
 46→// StreamOutcome — discriminated union for post-loop/catch resolution
 47→// ============================================================================
 48→
 49→export type StreamOutcome =
 50→  | { type: "cancelled" }
 51→  | { type: "completed"; stopReasonError: boolean }
 52→  | { type: "post_success_exit"; stopReasonError: boolean }
 53→  | { type: "genuine_error"; error: unknown; ownsSession: boolean };
 54→
 55→/**
 56→ * Resolves the stream outcome from the post-loop or catch context.
 57→ *
 58→ * This is a pure classification step — no side effects. Side effects
 59→ * are performed by executeOutcome() below.
 60→ *
 61→ * @param ctx       - accumulated stream context
 62→ * @param session   - session state (for cancelledByUser flag)
 63→ * @param error     - if called from catch, the thrown error; null for post-loop
 64→ * @param sessionId - for reference-identity ownership check
 65→ */
 66→export function resolveStreamOutcome(
 67→  ctx: StreamContext,
 68→  session: SessionState,
 69→  error: unknown | null,
 70→  sessionId: string
 71→): StreamOutcome {
 72→  // Cancel check — applies to both post-loop and catch paths.
 73→  // Cancel takes priority over all other outcomes.
 74→  if (session.cancelledByUser) {
 75→    return { type: "cancelled" };
 76→  }
 77→
 78→  // Post-loop path (error === null): normal completion
 79→  if (error === null) {
 80→    return { type: "completed", stopReasonError: ctx.stopReasonError };
 81→  }
 82→
 83→  // Catch path: post-success SIGINT — process exited after query completed.
 84→  // The CLI binary shuts down between turns, and the SDK reports any
 85→  // signal-based exit as an error. This is expected cleanup, not failure.
 86→  if (ctx.querySucceeded) {
 87→    return { type: "post_success_exit", stopReasonError: ctx.stopReasonError };
 88→  }
 89→
 90→  // Catch path: genuine error — check if this generator still owns the session.
 91→  // A rapid re-query can replace the session before the catch runs.
 92→  const currentSession = getSession(sessionId);
 93→  const ownsSession = !currentSession || currentSession === session;
 94→  return { type: "genuine_error", error, ownsSession };
 95→}
 96→
 97→// ============================================================================
 98→// executeOutcome — side effects via ts-pattern .exhaustive()
 99→// ============================================================================
100→
101→/**
102→ * Executes the side effects for a stream outcome.
103→ * Separated from resolveStreamOutcome so classification is testable as pure.
104→ */
105→export function executeOutcome(
106→  outcome: StreamOutcome,
107→  sessionId: string,
108→  ctx: StreamContext,
109→  options: { model?: string; resume?: string },
110→  generatorId: string
111→): void {
112→  match(outcome)
113→    .with({ type: "cancelled" }, () => {
114→      persistCancellation(sessionId, "claude", options.model || "opus");
115→      console.log(`[${generatorId}] Session cancelled by user: ${sessionId}`);
116→    })
117→    .with({ type: "completed" }, ({ stopReasonError }) => {
118→      // Normal completion — ensure session is marked idle.
119→      // Skip if a stop-reason error was already recorded (e.g. max_tokens).
120→      if (!stopReasonError) {
121→        updateSessionStatus(sessionId, "idle");
122→      }
123→      console.log(`[${generatorId}] Session completed: ${sessionId}`);
124→    })
125→    .with({ type: "post_success_exit" }, ({ stopReasonError }) => {
126→      // Process exited after successful query — expected cleanup.
127→      if (!stopReasonError) {
128→        updateSessionStatus(sessionId, "idle");
129→      }
130→      console.log(
131→        `[${generatorId}] Process exited after successful query (expected cleanup)`
132→      );
133→    })
134→    .with({ type: "genuine_error" }, ({ error, ownsSession }) => {
135→      const classified = classifyError(error);
136→      const rawErrorMsg = getErrorMessage(error);
137→      const errorName = error instanceof Error ? error.name : "non-Error";
138→      const errorStack = error instanceof Error
139→        ? error.stack?.split("\n").slice(0, 5).join("\n")
140→        : "no stack";
141→      // Extract any extra properties the SDK may attach (cause, code, exitCode, signal, etc.)
142→      const extraProps = error instanceof Error
143→        ? Object.getOwnPropertyNames(error)
144→            .filter((k) => !["message", "stack", "name"].includes(k))
145→            .map((k) => `${k}=${JSON.stringify((error as any)[k])}`)
146→            .join(" ")
147→        : "";
148→
149→      console.error(
150→        `[${generatorId}] Error in Claude query [${classified.category}]:`,
151→        classified.message
152→      );
153→      console.error(
154→        `[${generatorId}] Error details:`,
155→        `name=${errorName}`,
156→        `wasResume=${!!options.resume}`,
157→        `resumeId=${options.resume ?? "none"}`,
158→        `querySucceeded=${ctx.querySucceeded}`,
159→        `messageCount=${ctx.messageCount}`,
160→        extraProps ? `extraProps={${extraProps}}` : "extraProps={}",
161→      );
162→      console.error(`[${generatorId}] Stack (top 5):\n${errorStack}`);
163→
164→      if (ownsSession) {
165→        // Enrich process_exit errors with diagnostic context that would
166→        // otherwise only appear in /tmp/opendevs-*.log. For other categories
167→        // (auth, rate_limit, etc.) the SDK message is already descriptive.
168→        notifyAndRecordError(sessionId, "claude", classified, (c) => {
169→          if (c.category !== "process_exit") return c.message;
170→          const parts: string[] = [c.message];
171→          if (options.resume) parts.push("(resumed session)");
172→          if (ctx.messageCount > 0) {
173→            parts.push(`after ${ctx.messageCount} message${ctx.messageCount !== 1 ? "s" : ""}`);
174→          } else {
175→            parts.push("before receiving any messages");
176→          }
177→          if (ctx.lastResultError) parts.push(`— ${ctx.lastResultError}`);
178→          if (extraProps) parts.push(`[${extraProps}]`);
179→          return parts.join(" ");
180→        });
181→      }
182→    })
183→    .exhaustive();
184→}
185→

