 99→// ============================================================================
100→// ClaudeAgentHandler
101→// ============================================================================
102→
103→export class ClaudeAgentHandler implements AgentHandler {
104→  readonly agentType = "claude" as const;
105→
106→  initialize(): { success: boolean; error?: string } {
107→    return initializeClaude();
108→  }
109→
110→  async handleQuery(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
111→    const tHandleQuery = Date.now();
112→    console.log(`[TIMING][handleQuery] START session=${sessionId} promptLength=${prompt.length}`);
113→    if (blockIfNotInitialized(sessionId)) return;
114→
115→    const session = getSession(sessionId);
116→    const modelChanged = session?.currentModel !== options.model;
117→    const maxThinkingTokensChanged =
118→      session?.currentMaxThinkingTokens !== options.maxThinkingTokens;
119→    const settingsChangedFlag = settingsChanged(session?.currentSettings, options);
120→
121→    if (session) {
122→      session.turnId = options.turnId;
123→      session.cwd = options.cwd;
124→    }
125→
126→    const canReuse =
127→      isSessionActive(session) && options.shouldResetGenerator !== true && !settingsChangedFlag;
128→
129→    if (canReuse) {
130→      console.log(
131→        `[TIMING][handleQuery] REUSE session=${sessionId} decisionTime=${Date.now() - tHandleQuery}ms`
132→      );
133→
134→      // Hot-swap model if it changed
135→      if (modelChanged && session) {
136→        const query = getQuery(sessionId);
137→        if (query) {
138→          const envVars = options.claudeEnvVars ? parseEnvString(options.claudeEnvVars) : {};
139→          const mappedModel = mapModelForProvider(options.model, envVars);
140→          console.log(
141→            `Model changed from ${session.currentModel} to ${options.model}, using setModel callback`
142→          );
143→          try {
144→            await query.setModel(mappedModel);
145→            const updatedSession = getSession(sessionId);
146→            if (updatedSession) updatedSession.currentModel = options.model;
147→          } catch (error) {
148→            console.error(
149→              `Failed to update model: ${getErrorMessage(error)}`
150→            );
151→          }
152→        }
153→      }
154→
155→      // Hot-swap maxThinkingTokens if it changed
156→      const query = getQuery(sessionId);
157→      if (maxThinkingTokensChanged && session && query) {
158→        try {
159→          await query.setMaxThinkingTokens(options.maxThinkingTokens ?? null);
160→          session.currentMaxThinkingTokens = options.maxThinkingTokens;
161→        } catch (error) {
162→          console.error(
163→            `Failed to update maxThinkingTokens: ${getErrorMessage(error)}`
164→          );
165→        }
166→      }
167→
168→      // Update permission mode if provided
169→      if (query && options.permissionMode) {
170→        try {
171→          await query.setPermissionMode(options.permissionMode as PermissionMode);
172→        } catch (error) {
173→          console.error(
174→            `Failed to update permission mode: ${getErrorMessage(error)}`
175→          );
176→        }
177→      }
178→
179→      // Push the new prompt into the existing generator
180→      // isSessionActive type guard narrows sendMessage to be defined
181→      session.sendMessage(prompt);
182→    } else {
183→      const reason = !session
184→        ? "new session"
185→        : !isSessionActive(session)
186→          ? "no active generator"
187→          : options.shouldResetGenerator
188→            ? "should reset generator"
189→            : "settings changed";
190→      console.log(
191→        `[TIMING][handleQuery] NEW_GENERATOR session=${sessionId} reason="${reason}" decisionTime=${Date.now() - tHandleQuery}ms`
192→      );
193→
194→      if (isSessionActive(session)) {
195→        terminateSession(sessionId);
196→      }
197→
198→      const newSession: SessionState = {
199→        currentSettings: {
200→          claudeEnvVars: options.claudeEnvVars,
201→          additionalDirectories: options.additionalDirectories,
202→          chromeEnabled: options.chromeEnabled,
203→          strictDataPrivacy: options.strictDataPrivacy,
204→        },
205→        currentModel: options.model,
206→        currentMaxThinkingTokens: options.maxThinkingTokens,
207→        turnId: options.turnId,
208→        cwd: options.cwd,
209→      };
210→      setSession(sessionId, newSession);
211→
212→      void this.processWithGenerator(sessionId, prompt, options);
213→    }
214→  }
215→
216→  async handleCancel(sessionId: string): Promise<void> {
217→    console.log("Handling Claude cancel request for session:", sessionId);
218→    if (blockIfNotInitialized(sessionId)) return;
219→
220→    const query = getQuery(sessionId);
221→    const session = getSession(sessionId);
222→
223→    if (isSessionActive(session) && query) {
224→      console.log(`Force-closing query for session ${sessionId}`);
225→
226→      // 1. Flag cancellation so the post-loop path persists the cancelled message
227→      session.cancelledByUser = true;
228→
229→      // 2. Create checkpoint before process dies
230→      if (session.turnId && session.cwd) {
231→        createCheckpoint(sessionId, session.turnId, "end", session.cwd, "claudeHandler");
232→      }
233→
234→      // 3. Force kill: close() terminates CLI subprocess + all children + MCP transports
235→      query.close();
236→
237→      // 4. Signal prompt generator to stop — finally block owns cleanup
238→      terminateSession(sessionId);
239→    } else {
240→      console.log(`No active session found for ${sessionId} to cancel`);
241→    }
242→  }
243→
244→  handleReset(sessionId: string): void {
245→    console.log(`Handling reset generator request for session: ${sessionId}`);
246→    const session = getSession(sessionId);
247→    if (session) {
248→      console.log(`Terminating generator for session ${sessionId} on reset request`);
249→      terminateSession(sessionId);
250→    }
251→  }
252→
253→  // ==========================================================================
254→  // Claude-specific RPC methods (not part of AgentHandler interface)
255→  // ==========================================================================
256→
