268→  async workspaceInit(params: WorkspaceInitParams) {
269→    const { slashCommands, mcpServers, error } = await this.getClaudeWorkspaceInitData({
270→      cwd: params.cwd,
271→      ghToken: params.ghToken,
272→      claudeEnvVars: params.claudeEnvVars,
273→    });
274→    return {
275→      id: params.id,
276→      type: "workspace_init_output",
277→      agentType: "claude",
278→      slashCommands,
279→      mcpServers,
280→      error,
281→    };
282→  }
283→
284→  async updatePermissionMode(sessionId: string, permissionMode: string): Promise<void> {
285→    console.log(`Handling permission mode update for session ${sessionId}: ${permissionMode}`);
286→    const session = getSession(sessionId);
287→    const existingQuery = getQuery(sessionId);
288→
289→    if (!session) {
290→      console.log(`No active session found for ${sessionId}, ignoring permission mode update`);
291→      return;
292→    }
293→
294→    if (existingQuery) {
295→      try {
296→        await existingQuery.setPermissionMode(permissionMode as PermissionMode);
297→        console.log(`Permission mode updated to ${permissionMode} for session ${sessionId}`);
298→      } catch (error) {
299→        console.error(
300→          `Failed to update permission mode: ${getErrorMessage(error)}`
301→        );
302→      }
303→    }
304→  }
305→
306→  async getContextUsage(request: ContextUsageRequest) {
307→    const { id: sessionId, options } = request;
308→    const claudeSessionId = options.claudeSessionId;
309→
310→    console.log(
311→      `[getContextUsage] Getting context usage for session: ${sessionId}, claudeSessionId: ${claudeSessionId}`
312→    );
313→
314→    if (!claudeSessionId) throw new Error("No claudeSessionId provided");
315→    if (blockIfNotInitialized(sessionId)) throw new Error("Initialization failure");
316→
317→    const sdkOptions = {
318→      cwd: options.cwd,
319→      pathToClaudeCodeExecutable: getClaudeExecutablePath(),
320→      systemPrompt: DEFAULT_PROMPT,
321→      settingSources: DEFAULT_SETTING_SOURCES,
322→      resume: claudeSessionId,
323→    };
324→
325→    const contextUsageQuery = claudeSDK({ prompt: "/context", options: sdkOptions });
326→
327→    try {
328→      for await (const message of contextUsageQuery) {
329→        if (message.type !== "user") continue;
330→        return {
331→          type: "context_usage",
332→          id: sessionId,
333→          agentType: "claude",
334→          contextUsageData: message,
335→        };
336→      }
337→    } finally {
338→      try {
339→        await contextUsageQuery.interrupt();
340→      } catch (error) {
341→        console.error(`[getContextUsage] Error during interrupt:`, error);
342→      }
343→    }
344→
345→    throw new Error("No user message found in context usage response");
346→  }
