407→  /**
408→   * Creates an async-generator-backed Claude SDK session.
409→   * Uses a message queue for multi-turn conversations.
410→   */
411→  private async processWithGenerator(
412→    sessionId: string,
413→    initialPrompt: string,
414→    options: QueryOptions
415→  ): Promise<void> {
416→    const tProcessStart = Date.now();
417→    const generatorId = `${sessionId}/${tProcessStart}`;
418→    const session = getSession(sessionId);
419→    if (!session) {
420→      console.error(`[${generatorId}] Session ${sessionId} not found`);
421→      return;
422→    }
423→    console.log(`[TIMING][${generatorId}] processWithGenerator START`);
424→
425→    // --- Message queue for multi-turn conversations ---
426→    const promptQueue = new AsyncQueue<string>([initialPrompt]);
427→
428→    session.sendMessage = (message: string) => {
429→      console.log(`[${generatorId}] Pushing message to queue`);
430→      promptQueue.push(message);
431→    };
432→
433→    session.sendTerminate = () => {
434→      console.log(`[${generatorId}] Sending terminate signal`);
435→      promptQueue.close();
436→    };
437→
438→    // Mutable context accumulated during the streaming loop.
439→    // Replaces scattered boolean flags — see stream-context.ts for field docs.
440→    const ctx = createStreamContext();
441→
442→    try {
443→      // Build environment using shared env-builder
444→      const tEnvStart = Date.now();
445→      const envForClaude = buildAgentEnvironment({
446→        claudeEnvVars: options?.claudeEnvVars,
447→        opendevsEnv: options?.opendevsEnv,
448→        ghToken: options?.ghToken,
449→        extraEnv: { CLAUDE_CODE_ENABLE_TASKS: "true" },
450→      });
451→      console.log(
452→        `[TIMING][${generatorId}] buildAgentEnvironment took ${Date.now() - tEnvStart}ms`
453→      );
454→
455→      // Auto-inject resume for session continuity after sidecar restart.
456→      // If no explicit resume was provided and a previous agent_session_id
457→      // exists in the DB, inject it so the SDK resumes the conversation
458→      // with full context (message history, tool state).
459→      // Skip when shouldResetGenerator is true — the user explicitly wants a clean start.
460→      const tResumeStart = Date.now();
461→      if (!options.resume && !options.shouldResetGenerator) {
462→        const savedAgentSessionId = lookupAgentSessionId(sessionId);
463→        if (savedAgentSessionId) {
464→          console.log(
465→            `[${generatorId}] Auto-resuming session with agent_session_id ${savedAgentSessionId}`
466→          );
467→          options = { ...options, resume: savedAgentSessionId };
468→        }
469→      }
470→      console.log(
471→        `[TIMING][${generatorId}] resumeLookup took ${Date.now() - tResumeStart}ms resume=${!!options.resume} resumeId=${options.resume ?? "none"}`
472→      );
473→      if (options.resume) {
474→        console.log(
475→          `[RESUME-DEBUG][${generatorId}] Attempting resume with agent_session_id=${options.resume} for session=${sessionId}`
476→        );
477→      }
478→
479→      // Build SDK options using the dedicated builder
480→      const tSdkOptsStart = Date.now();
481→      const sdkOptions = buildSdkOptions(sessionId, envForClaude, options);
482→      console.log(`[TIMING][${generatorId}] buildSdkOptions took ${Date.now() - tSdkOptsStart}ms`);
483→
484→      const promptInput = buildPromptIterable(promptQueue, sessionId);
485→
486→      // Start the SDK query
487→      console.log(
488→        `[TIMING][${generatorId}] SDK spawn starting (elapsed since processStart: ${Date.now() - tProcessStart}ms)`
489→      );
490→      console.log(
491→        `[RESUME-DEBUG][${generatorId}] SDK options: resume=${sdkOptions.resume ?? "none"} cwd=${sdkOptions.cwd} model=${sdkOptions.model} permissionMode=${sdkOptions.permissionMode}`
492→      );
493→      const tSdkSpawn = Date.now();
494→      const queryResult = claudeSDK({ prompt: promptInput, options: sdkOptions });
495→      console.log(
496→        `[TIMING][${generatorId}] claudeSDK() constructor returned in ${Date.now() - tSdkSpawn}ms`
497→      );
498→
499→      setQuery(sessionId, queryResult);
500→      session.generator = queryResult[Symbol.asyncIterator]();
501→
502→      // Per-message options (constant for the lifetime of this generator)
503→      const msgOpts: ProcessMessageOptions = {
504→        sessionId,
505→        generatorId,
506→        model: options.model || "opus",
507→        isResume: !!options.resume,
508→      };
509→
510→      // Stream messages back to the frontend and persist to DB.
511→      // IMPORTANT: Persist to DB BEFORE notifying frontend, so messages
512→      // are in the DB when the frontend receives the event and fetches them.
513→      const tStreamStart = Date.now();
514→      for await (const message of queryResult) {
515→        ctx.messageCount++;
516→        if (ctx.firstMessageTime === null) {
517→          ctx.firstMessageTime = Date.now();
518→          console.log(
519→            `[TIMING][${generatorId}] FIRST_MESSAGE received after ${ctx.firstMessageTime - tSdkSpawn}ms (type=${(message as any)?.type})`
520→          );
521→        }
522→        // Deserialize, persist, and forward to frontend.
523→        // See message-processor.ts for the critical side-effect ordering.
524→        if (message) {
525→          const cleanMessage = deserializeMessage(message, generatorId);
526→          if (!cleanMessage) continue;
527→
528→          processMessage(cleanMessage, ctx, session, msgOpts);
529→
530→          // Log per-message timing for first 5 messages, then every 10th
531→          if (ctx.messageCount <= 5 || ctx.messageCount % 10 === 0) {
532→            console.log(
533→              `[TIMING][${generatorId}] msg#${ctx.messageCount} type=${cleanMessage.type}${cleanMessage.type === "result" ? "/" + cleanMessage.subtype : ""} elapsed=${Date.now() - tStreamStart}ms`
534→            );
535→          }
536→        }
537→      }
538→
539→      console.log(
540→        `[TIMING][${generatorId}] STREAM_COMPLETE messages=${ctx.messageCount} totalStreamTime=${Date.now() - tStreamStart}ms totalProcessTime=${Date.now() - tProcessStart}ms`
541→      );
542→
543→      // Resolve outcome and execute side effects (cancel, idle, error).
544→      // See stream-context.ts for the classification logic.
545→      const postLoopOutcome = resolveStreamOutcome(ctx, session, null, sessionId);
546→      executeOutcome(postLoopOutcome, sessionId, ctx, options, generatorId);
547→      if (postLoopOutcome.type === "cancelled") return;
548→    } catch (error) {
549→      // Resolve outcome from the catch context — covers cancel-via-throw,
550→      // post-success SIGINT, and genuine errors.
551→      const catchOutcome = resolveStreamOutcome(ctx, session, error, sessionId);
552→      executeOutcome(catchOutcome, sessionId, ctx, options, generatorId);
553→      if (catchOutcome.type !== "genuine_error") return;
554→    } finally {
555→      // Only clean up if this generator still owns the session.
556→      // A rapid re-query can replace the session before this finally runs;
557→      // blindly deleting would wipe the new session's state.
558→      const currentSession = getSession(sessionId);
559→      if (!currentSession || currentSession === session) {
560→        deleteQuery(sessionId);
561→        deleteSession(sessionId);
562→      }
563→    }
564→  }
565→}
