  1→// sidecar/agents/codex/codex-handler.ts
  2→// CodexAgentHandler — implements AgentHandler for the OpenAI Codex SDK.
  3→// Mirrors the Claude handler architecture: streaming events, DB persistence,
  4→// frontend notifications via FrontendClient.
  5→
  6→// Type-only imports are erased at compile time — safe for CJS bundling.
  7→// The runtime Codex class is loaded via dynamic import() in processQuery()
  8→// because @openai/codex-sdk is ESM-only and uses import.meta.url at module
  9→// init, which can't be shimmed in esbuild's CJS output.
 10→import type { ThreadItem, ThreadOptions } from "@openai/codex-sdk";
 11→import { match, P } from "ts-pattern";
 12→import { FrontendClient } from "../../frontend-client";
 13→import { classifyError } from "../error-classifier";
 14→import { persistCancellation, notifyAndRecordError } from "../query-lifecycle";
 15→import { saveAssistantMessage, updateSessionStatus } from "../../db/session-writer";
 16→import type { AgentHandler, QueryOptions } from "../agent-handler";
 17→import { buildAgentEnvironment } from "../env-builder";
 18→import { buildWorkspaceContext } from "../workspace-context";
 19→import { initializeCodex, blockIfNotInitialized, getCodexExecutablePath } from "./codex-discovery";
 20→import { resolveCodexModel } from "./codex-models";
 21→import {
 22→  getCodexSession,
 23→  setCodexSession,
 24→  deleteCodexSession,
 25→  abortCodexSession,
 26→  type CodexSessionState,
 27→} from "./codex-session";
 28→
 29→// ============================================================================
 30→// Message Format Mapping
 31→// ============================================================================
 32→
 33→/**
 34→ * Maps a Codex ThreadItem to Claude-compatible content blocks.
 35→ * The frontend renders messages using Claude's format (TextBlock, ToolUseBlock,
 36→ * ToolResultBlock, ThinkingBlock), so we produce the same shape.
 37→ */
 38→function mapItemToContentBlocks(item: ThreadItem): unknown[] {
 39→  return match(item)
 40→    .with({ type: "agent_message" }, (i) => [{ type: "text", text: i.text }])
 41→    .with({ type: "reasoning" }, (i) => [{ type: "thinking", thinking: i.text }])
 42→    .with({ type: "command_execution" }, (cmd) => {
 43→      const toolUseId = `codex-cmd-${cmd.id}`;
 44→      const blocks: unknown[] = [
 45→        {
 46→          type: "tool_use",
 47→          id: toolUseId,
 48→          name: "Bash",
 49→          input: { command: cmd.command },
 50→        },
 51→      ];
 52→      if (cmd.status === "completed" || cmd.status === "failed") {
 53→        blocks.push({
 54→          type: "tool_result",
 55→          tool_use_id: toolUseId,
 56→          content: cmd.aggregated_output || `Exit code: ${cmd.exit_code ?? "unknown"}`,
 57→          is_error: cmd.status === "failed" || (cmd.exit_code !== undefined && cmd.exit_code !== 0),
 58→        });
 59→      }
 60→      return blocks;
 61→    })
 62→    .with({ type: "file_change" }, (fc) => {
 63→      const toolUseId = `codex-file-${fc.id}`;
 64→      const summary = fc.changes.map((c) => `${c.kind}: ${c.path}`).join("\n");
 65→      return [
 66→        {
 67→          type: "tool_use",
 68→          id: toolUseId,
 69→          name: "Edit",
 70→          input: {
 71→            file_path: fc.changes[0]?.path ?? "unknown",
 72→            description: summary,
 73→          },
 74→        },
 75→        {
 76→          type: "tool_result",
 77→          tool_use_id: toolUseId,
 78→          content: summary,
 79→          is_error: fc.status === "failed",
 80→        },
 81→      ];
 82→    })
 83→    .with({ type: "mcp_tool_call" }, (mcp) => {
 84→      const toolUseId = `codex-mcp-${mcp.id}`;
 85→      const blocks: unknown[] = [
 86→        {
 87→          type: "tool_use",
 88→          id: toolUseId,
 89→          name: `${mcp.server}:${mcp.tool}`,
 90→          input: mcp.arguments ?? {},
 91→        },
 92→      ];
 93→      if (mcp.status === "completed" || mcp.status === "failed") {
 94→        blocks.push({
 95→          type: "tool_result",
 96→          tool_use_id: toolUseId,
 97→          content: mcp.error?.message ?? JSON.stringify(mcp.result ?? ""),
 98→          is_error: mcp.status === "failed",
 99→        });
100→      }
101→      return blocks;
102→    })
103→    .with({ type: "web_search" }, (ws) => [
104→      {
105→        type: "tool_use",
106→        id: `codex-ws-${ws.id}`,
107→        name: "WebSearch",
108→        input: { query: ws.query },
109→      },
110→    ])
111→    .with({ type: "todo_list" }, (todo) => {
112→      const text = todo.items.map((t) => `${t.completed ? "[x]" : "[ ]"} ${t.text}`).join("\n");
113→      return [{ type: "text", text: `**Plan:**\n${text}` }];
114→    })
115→    .with({ type: "error" }, (i) => [{ type: "text", text: `Error: ${i.message}` }])
116→    .otherwise((i) => {
117→      // External SDK types can gain new variants — gracefully ignore unknown items
118→      console.warn(`[codex] Unknown ThreadItem type: ${(i as any).type}`);
119→      return [];
120→    });
121→}
