    session.generator = queryResult[Symbol.asyncIterator]();

    // Per-message options (constant for the lifetime of this generator)
    const msgOpts: ProcessMessageOptions = {
      sessionId,
      generatorId,
      model: options.model || "opus",
      isResume: !!options.resume,
